type ResourceKind = "warehouse" | "location" | "item" | "batch" | "serial" | "stockEntry" | "balance" | "ledger" | "reservation" | "cycleCount";
interface ListRow { id: string; code: string; name: string; status: string; quantity: string; version: number; allowedCommands: AllowedCommand[] }
interface DetailRecord { id: string; title: string; subtitle: string; version: number; fields: { label: string; value: string }[]; allowedCommands: AllowedCommand[] }
interface FieldDefinition { key: string; label: string; required?: boolean; type?: "text" | "number" | "date" | "datetime-local"; hint?: string; defaultValue?: string }
type FormValues = Record<string, string>;
interface ResourceDescriptor {
  title: string; singular: string; description: string; listPath: string; createPath?: string; detailPath: string; editPath?: string; readOnly?: boolean;
  fields: readonly FieldDefinition[];
  list: (filters: { page: number; page_size: number; search?: string; ordering?: string }) => Promise<InventoryPage<ListRow>>;
  detail: (id: string) => Promise<InventoryResult<DetailRecord>>;
  create?: (values: FormValues, key: string) => Promise<InventoryResult<DetailRecord>>;
  update?: (id: string, values: FormValues, version: number) => Promise<InventoryResult<DetailRecord>>;
  runCommand?: (id: string, name: string, version: number, key: string) => Promise<InventoryResult<DetailRecord>>;
}

const text = (value: unknown): string => {
  if (value === null || value === undefined || value === "") return "—";
  if (typeof value === "string") return value;
  if (typeof value === "number" || typeof value === "bigint") return value.toString();
  if (typeof value === "boolean") return value ? "Yes" : "No";
  return "Available";
};
const nullable = (value: string | undefined): string | null => value?.trim() ? value : null;
const replaceId = (path: string, id: string) => path.replace(":id", encodeURIComponent(id));
const replaceEnvironment = (path: string, environment: string) => path.replace(":environment", encodeURIComponent(environment));
const tenantId = () => useAuthStore.getState().user?.tenant_id ?? "unscoped";
const mappedPage = <T,>(result: InventoryPage<T>, mapper: (item: T) => ListRow): InventoryPage<ListRow> => ({ ...result, data: result.data.map(mapper) });
const mappedResult = <T,>(result: InventoryResult<T>, mapper: (item: T) => DetailRecord): InventoryResult<DetailRecord> => ({ ...result, data: mapper(result.data) });
const fields = (pairs: readonly (readonly [string, unknown])[]) => pairs.map(([label, value]) => ({ label, value: text(value) }));
const governance = (resource: { allowed_commands?: AllowedCommand[] }) => resource.allowed_commands ?? [];

const warehouseDetail = (item: Warehouse): DetailRecord => ({ id: item.id, title: item.warehouse_name, subtitle: item.warehouse_code, version: item.version, allowedCommands: governance(item), fields: fields([["Type", item.warehouse_type], ["Country", item.country_code], ["Timezone", item.timezone], ["Default", item.is_default ? "Yes" : "No"], ["Status", item.is_active ? "Active" : "Inactive"], ["City", item.city]]) });
const locationDetail = (item: StorageLocation): DetailRecord => ({ id: item.id, title: item.location_name, subtitle: item.location_code, version: item.version, allowedCommands: governance(item), fields: fields([["Warehouse", item.warehouse.name], ["Zone", item.zone_type], ["Location type", item.location_type], ["Barcode", item.barcode], ["Pick sequence", item.pick_sequence], ["Status", item.is_active ? "Active" : "Inactive"]]) });
const itemDetail = (item: Item): DetailRecord => ({ id: item.id, title: item.item_name, subtitle: item.item_code, version: item.version, allowedCommands: governance(item), fields: fields([["Base UOM", item.base_uom], ["Tracking", item.tracking_mode], ["Valuation", item.valuation_method], ["Available category", item.category], ["Reorder point", item.reorder_point], ["Status", item.is_active ? "Active" : "Inactive"]]) });
