const serialDetail = (item: SerialNumber): DetailRecord => ({ id: item.id, title: item.serial_number, subtitle: item.item.name, version: item.version, allowedCommands: governance(item), fields: fields([["Status", item.status], ["Warehouse", item.current_warehouse?.name], ["Location", item.current_location?.name], ["Manufacturer", item.manufacturer], ["Model", item.model_number]]) });
const entryDetail = (item: StockEntry): DetailRecord => ({ id: item.id, title: item.entry_number, subtitle: item.entry_type, version: item.version, allowedCommands: governance(item), fields: fields([["Status", item.status], ["Posting time", item.posting_at], ["Source", item.source_warehouse?.name], ["Destination", item.destination_warehouse?.name], ["Lines", item.lines.length], ["Reason", item.reason]]) });
const reservationDetail = (item: StockReservation): DetailRecord => ({ id: item.id, title: item.reservation_number, subtitle: item.item.name, version: item.version, allowedCommands: governance(item), fields: fields([["Status", item.status], ["Warehouse", item.warehouse.name], ["Location", item.location?.name], ["Quantity", item.quantity], ["Expires", item.expires_at], ["Reference", `${item.reference_module} / ${item.reference_type}`]]) });
const countDetail = (item: CycleCount): DetailRecord => ({ id: item.id, title: item.count_number, subtitle: item.count_type, version: item.version, allowedCommands: governance(item), fields: fields([["Status", item.status], ["Warehouse", item.warehouse.name], ["Location", item.location?.name], ["Scheduled", item.scheduled_for], ["Lines", item.lines.length]]) });

