function ResourceListPage({ kind }: { kind: ResourceKind }) {
  const descriptor = resourceDescriptors[kind]; const navigate = useNavigate(); const [params, setParams] = useSearchParams();
  const [selected, setSelected] = useState<string[]>([]);
  const page = Math.max(1, Number(params.get("page")) || 1); const search = params.get("search") ?? ""; const ordering = params.get("ordering") ?? "code";
  const filters = useMemo(() => ({ page, page_size: 25, search: search || undefined, ordering }), [page, search, ordering]);
  const queryState = useQuery({ queryKey: inventoryQueryKeys.list(tenantId(), kind, filters), queryFn: () => descriptor.list(filters) });
  if (queryState.isLoading) return <InventorySkeleton label={`Loading ${descriptor.title}`} />;
  if (queryState.error) return <InventoryErrorState error={queryState.error} onRetry={() => void queryState.refetch()} />;
  const rows = queryState.data?.data ?? []; const pagination = queryState.data?.pagination;
  const set = (key: string, value: string) => { const next = new URLSearchParams(params); if (value) next.set(key, value); else next.delete(key); if (key !== "page") next.set("page", "1"); setParams(next); };
  const exportCsv = () => { const included = selected.length ? rows.filter((row) => selected.includes(row.id)) : rows; const quote = (value: string) => `"${value.replaceAll('"', '""')}"`; const content = ["code,description,status,operational_detail", ...included.map((row) => [row.code, row.name, row.status, row.quantity].map(quote).join(","))].join("\n"); const href = URL.createObjectURL(new Blob([content], { type: "text/csv" })); const anchor = document.createElement("a"); anchor.href = href; anchor.download = `${kind}-inventory.csv`; anchor.click(); URL.revokeObjectURL(href); };
  const saveFilter = () => localStorage.setItem(`inventory-filter:${tenantId()}:${kind}`, params.toString());
  return <InventoryPageShell title={descriptor.title} description={descriptor.description} actions={<><Button variant="outline" onClick={saveFilter}>Save filter</Button><Button variant="outline" disabled={!rows.length} onClick={exportCsv}><Download className="mr-2 h-4 w-4" />Export CSV</Button>{descriptor.createPath ? <><Button variant="outline" onClick={() => navigate(ROUTES.IMPORT)}>Import</Button><Button onClick={() => navigate(descriptor.createPath!)}><Plus className="mr-2 h-4 w-4" />Create {descriptor.singular}</Button></> : kind === "balance" ? <Button variant="outline" onClick={() => navigate(ROUTES.STOCK_LEDGER)}>Open ledger</Button> : null}</>}>
    <Card className="p-4"><div className="grid gap-3 sm:grid-cols-[minmax(0,1fr)_14rem]"><Label className="sr-only" htmlFor={`${kind}-search`}>Search {descriptor.title}</Label><div className="relative"><Search className="absolute left-3 top-2.5 h-4 w-4 text-muted-foreground" /><Input id={`${kind}-search`} value={search} onChange={(event) => set("search", event.target.value)} className="pl-9" placeholder={`Search ${descriptor.title.toLowerCase()}`} /></div><select aria-label="Order results" value={ordering} onChange={(event) => set("ordering", event.target.value)} className="h-10 rounded-md border border-input bg-background px-3 text-sm"><option value="code">Code</option><option value="-created_at">Newest first</option><option value="created_at">Oldest first</option></select></div></Card>
    {rows.length === 0 ? <InventoryEmpty title={`No ${descriptor.title.toLowerCase()} found`} detail={search ? "No records match these URL-backed filters. Clear the search or adjust filters." : `Create the first ${descriptor.singular} to begin this operational workflow.`} action={descriptor.createPath ? { label: `Create ${descriptor.singular}`, onClick: () => navigate(descriptor.createPath!) } : kind === "ledger" ? { label: "Create a stock entry", onClick: () => navigate(ROUTES.STOCK_ENTRY_NEW) } : undefined} /> : <Card className="overflow-x-auto"><table className="min-w-full text-sm"><thead className="border-b bg-muted/50 text-left"><tr><th className="px-4 py-3"><span className="sr-only">Select</span></th><th className="px-4 py-3">Code</th><th className="px-4 py-3">Description</th><th className="px-4 py-3">Status</th><th className="px-4 py-3">Operational detail</th><th className="px-4 py-3 text-right">Open</th></tr></thead><tbody>{rows.map((row) => <tr key={row.id} className="border-b last:border-0 hover:bg-muted/30"><td className="px-4 py-3"><input type="checkbox" aria-label={`Select ${row.code}`} checked={selected.includes(row.id)} onChange={(event) => setSelected((current) => event.target.checked ? [...current, row.id] : current.filter((id) => id !== row.id))} /></td><td className="px-4 py-3 font-medium">{row.code}</td><td className="px-4 py-3">{row.name}</td><td className="px-4 py-3"><span className="rounded-full bg-muted px-2 py-1 text-xs">{row.status}</span></td><td className="px-4 py-3 text-muted-foreground">{row.quantity}</td><td className="px-4 py-3 text-right"><Button variant="ghost" size="sm" onClick={() => navigate(replaceId(descriptor.detailPath, row.id))}>View <ExternalLink className="ml-2 h-3 w-3" /></Button></td></tr>)}</tbody></table></Card>}
    {pagination ? <nav className="flex items-center justify-between" aria-label={`${descriptor.title} pagination`}><p className="text-sm text-muted-foreground">Page {pagination.page} of {Math.max(1, pagination.total_pages)} · {pagination.total_count} records</p><div className="flex gap-2"><Button variant="outline" disabled={!pagination.previous} onClick={() => set("page", String(page - 1))}><ChevronLeft className="mr-1 h-4 w-4" />Previous</Button><Button variant="outline" disabled={!pagination.next} onClick={() => set("page", String(page + 1))}>Next<ChevronRight className="ml-1 h-4 w-4" /></Button></div></nav> : null}
  </InventoryPageShell>;
}

function ResourceDetailPage({ kind }: { kind: ResourceKind }) {
  const descriptor = resourceDescriptors[kind]; const { id = "" } = useParams(); const navigate = useNavigate(); const queryClient = useQueryClient();
  const state = useQuery({ queryKey: inventoryQueryKeys.detail(tenantId(), kind, id), queryFn: () => descriptor.detail(id), enabled: Boolean(id) });
  const commandMutation = useMutation({ mutationFn: ({ command, key }: { command: AllowedCommand; key: string }) => { if (!descriptor.runCommand) throw new Error("This resource has no command endpoint."); return descriptor.runCommand(id, command.name, state.data?.data.version ?? 0, key); }, onSuccess: async () => { await queryClient.invalidateQueries({ queryKey: inventoryQueryKeys.resource(tenantId(), kind) }); await queryClient.invalidateQueries({ queryKey: inventoryQueryKeys.dashboard(tenantId()) }); } });
  if (state.isLoading) return <InventorySkeleton label={`Loading ${descriptor.singular}`} />; if (state.error) return <InventoryErrorState error={state.error} onRetry={() => void state.refetch()} />; const record = state.data?.data; if (!record) return <InventoryErrorState error={new ApiError("Record unavailable", 404)} />;
  const run = (cmd: AllowedCommand) => { const consequence = cmd.destructive ? "This action may be irreversible and will be audited." : "This state change will be audited."; if (!cmd.requires_confirmation || window.confirm(`${cmd.label} ${record.title}? ${consequence}`)) commandMutation.mutate({ command: cmd, key: createIdempotencyKey(`${kind}:${cmd.name}:${id}`) }); };
  return <InventoryPageShell title={record.title} description={record.subtitle} actions={<><Button variant="outline" onClick={() => navigate(descriptor.listPath)}><ArrowLeft className="mr-2 h-4 w-4" />Back</Button>{descriptor.editPath && !descriptor.readOnly ? <Button variant="outline" onClick={() => navigate(replaceId(descriptor.editPath!, id))}>Edit</Button> : null}{record.allowedCommands.map((cmd) => <Button key={cmd.name} variant={cmd.destructive ? "danger" : "primary"} disabled={commandMutation.isPending} onClick={() => run(cmd)}>{commandMutation.isPending ? "Working…" : cmd.label}</Button>)}</>}>
    {commandMutation.error ? <InventoryErrorState error={commandMutation.error} /> : null}<Card className="p-5"><dl className="grid gap-x-8 gap-y-5 sm:grid-cols-2 lg:grid-cols-3">{record.fields.map((field) => <div key={field.label}><dt className="text-xs font-medium uppercase tracking-wide text-muted-foreground">{field.label}</dt><dd className="mt-1 break-words text-sm font-medium">{field.value}</dd></div>)}</dl></Card><Card className="flex items-start gap-3 p-4"><ShieldCheck className="mt-0.5 h-5 w-5 text-primary" /><div><h2 className="font-medium">Server-governed commands</h2><p className="text-sm text-muted-foreground">Only commands authorized by the API are displayed. Hidden actions cannot bypass server authorization.</p></div></Card>
  </InventoryPageShell>;
}

function ResourceFormPage({ kind, mode }: { kind: ResourceKind; mode: "create" | "edit" }) {
  const descriptor = resourceDescriptors[kind]; const { id = "" } = useParams(); const navigate = useNavigate(); const queryClient = useQueryClient();
  const initial = useMemo(() => Object.fromEntries(descriptor.fields.map((field) => [field.key, field.defaultValue ?? ""])), [descriptor]); const [values, setValues] = useState<FormValues>(initial); const [dirty, setDirty] = useState(false); const [clientErrors, setClientErrors] = useState<FormValues>({}); const keyRef = useRef(createIdempotencyKey(`${kind}:create`));
  useEffect(() => { const beforeUnload = (event: BeforeUnloadEvent) => { if (dirty) { event.preventDefault(); event.returnValue = ""; } }; window.addEventListener("beforeunload", beforeUnload); return () => window.removeEventListener("beforeunload", beforeUnload); }, [dirty]);
  const detailState = useQuery({ queryKey: inventoryQueryKeys.detail(tenantId(), kind, id), queryFn: () => descriptor.detail(id), enabled: mode === "edit" && Boolean(id) });
  const mutation = useMutation({ mutationFn: () => { if (mode === "create") { if (!descriptor.create) throw new Error("Create is unavailable for this resource."); return descriptor.create(values, keyRef.current); } if (!descriptor.update) throw new Error("Update is unavailable for this resource."); return descriptor.update(id, values, detailState.data?.data.version ?? 0); }, onSuccess: async (result) => { setDirty(false); await queryClient.invalidateQueries({ queryKey: inventoryQueryKeys.resource(tenantId(), kind) }); await queryClient.invalidateQueries({ queryKey: inventoryQueryKeys.dashboard(tenantId()) }); navigate(replaceId(descriptor.detailPath, result.data.id)); } });
  const submit = (event: React.FormEvent) => { event.preventDefault(); const errors: FormValues = {}; descriptor.fields.forEach((field) => { if (field.required && !(values[field.key] ?? "").trim()) errors[field.key] = `${field.label} is required.`; }); if (kind === "stockEntry" && Number(values.line_quantity) <= 0) errors.line_quantity = "Quantity must be greater than zero."; if (kind === "reservation" && Number(values.quantity) <= 0) errors.quantity = "Quantity must be greater than zero."; setClientErrors(errors); if (Object.keys(errors).length === 0) mutation.mutate(); };
  if (mode === "edit" && detailState.isLoading) return <InventorySkeleton label={`Loading ${descriptor.singular} form`} />; if (detailState.error) return <InventoryErrorState error={detailState.error} onRetry={() => void detailState.refetch()} />;
  return <InventoryPageShell title={`${mode === "create" ? "Create" : "Edit"} ${descriptor.singular}`} description={mode === "create" ? "Required fields are validated here and again by the tenant-scoped service." : "Optimistic version matching prevents accidental overwrites."} actions={<Button variant="outline" onClick={() => { if (!dirty || window.confirm("Discard unsaved changes?")) navigate(mode === "edit" ? replaceId(descriptor.detailPath, id) : descriptor.listPath); }}>Cancel</Button>}>
    {mutation.error ? <InventoryErrorState error={mutation.error} /> : null}<form onSubmit={submit} noValidate><Card className="grid gap-5 p-5 sm:grid-cols-2">{descriptor.fields.map((field) => <div key={field.key} className="space-y-2"><Label htmlFor={`${kind}-${field.key}`}>{field.label}{field.required ? <span aria-hidden="true"> *</span> : null}</Label><Input id={`${kind}-${field.key}`} type={field.type ?? "text"} value={values[field.key] ?? ""} aria-invalid={Boolean(clientErrors[field.key])} aria-describedby={`${kind}-${field.key}-help`} onChange={(event) => { setValues((current) => ({ ...current, [field.key]: event.target.value })); setDirty(true); setClientErrors((current) => ({ ...current, [field.key]: "" })); }} /> <p id={`${kind}-${field.key}-help`} className={`text-xs ${clientErrors[field.key] ? "text-destructive" : "text-muted-foreground"}`}>{clientErrors[field.key] ?? field.hint ?? " "}</p></div>)}<div className="sm:col-span-2 flex justify-end"><Button type="submit" disabled={mutation.isPending}>{mutation.isPending ? "Saving…" : mode === "create" ? `Create ${descriptor.singular}` : "Save changes"}</Button></div></Card></form>
  </InventoryPageShell>;
}

export function InventoryDashboardPage() { const navigate = useNavigate(); const state = useQuery({ queryKey: inventoryQueryKeys.dashboard(tenantId()), queryFn: inventoryService.dashboard }); if (state.isLoading) return <InventorySkeleton label="Loading inventory dashboard" />; if (state.error) return <InventoryErrorState error={state.error} onRetry={() => void state.refetch()} />; const dashboard = state.data?.data; return <InventoryPageShell title="Inventory command center" description="Real-time stock health, actionable exceptions, and a guided path from first warehouse to first issue." actions={<Button onClick={() => navigate(ROUTES.STOCK_ENTRY_NEW)}><Plus className="mr-2 h-4 w-4" />New stock entry</Button>}><section className="grid gap-4 sm:grid-cols-2 xl:grid-cols-4">{dashboard?.metrics.map((metric) => <Card key={metric.label} className="p-5"><p className="text-sm text-muted-foreground">{metric.label}</p><p className="mt-2 text-3xl font-bold">{metric.value}</p>{metric.trend ? <p className="mt-1 text-xs text-muted-foreground">{metric.trend}</p> : null}</Card>)}</section>{dashboard?.alerts.length ? <Card className="divide-y"><h2 className="p-4 text-lg font-semibold">Action required</h2>{dashboard.alerts.map((alert) => <button key={alert.id} className="flex w-full items-start justify-between gap-4 p-4 text-left hover:bg-muted/40" onClick={() => navigate(alert.resource_url)}><span><strong>{alert.title}</strong><span className="mt-1 block text-sm text-muted-foreground">{alert.detail}</span></span><span className="rounded-full bg-muted px-2 py-1 text-xs">{alert.severity}</span></button>)}</Card> : <InventoryEmpty title="No inventory exceptions" detail="There are no current low-stock, expiry, count, or posting alerts." action={{ label: "View stock balances", onClick: () => navigate(ROUTES.STOCK_BALANCES) }} />}</InventoryPageShell>; }

const env = (value: string | undefined): Environment => value === "staging" || value === "production" ? value : "development";
const configDetail = (item: InventoryConfiguration): DetailRecord => ({ id: item.environment, title: `${item.environment} configuration`, subtitle: `Revision ${item.active_revision} · ${item.status}`, version: item.version, allowedCommands: governance(item), fields: fields([["Default valuation", item.default_valuation_method], ["Negative stock", item.allow_negative_stock ? "Allowed" : "Blocked"], ["Entry approval", item.require_stock_entry_approval ? "Required" : "Not required"], ["Creator/approver separation", item.enforce_creator_approver_separation ? "Enforced" : "Not enforced"], ["Maximum entry lines", item.max_lines_per_entry], ["Reservation TTL", `${item.reservation_ttl_minutes} minutes`], ["Expiry warning", `${item.expiry_warning_days} days`]]) });
export function ConfigurationListPage() { const navigate = useNavigate(); const state = useQuery({ queryKey: inventoryQueryKeys.resource(tenantId(), "configuration"), queryFn: inventoryService.listConfigurations }); if (state.isLoading) return <InventorySkeleton label="Loading inventory settings" />; if (state.error) return <InventoryErrorState error={state.error} onRetry={() => void state.refetch()} />; return <InventoryPageShell title="Inventory settings" description="Environment-specific, versioned, audited configuration with preview, import/export, activation, and rollback.">{state.data?.data.length ? <div className="grid gap-4 md:grid-cols-3">{state.data.data.map((item) => <Card key={item.environment} className="p-5"><h2 className="text-lg font-semibold capitalize">{item.environment}</h2><p className="mt-1 text-sm text-muted-foreground">{item.status} · revision {item.active_revision}</p><Button className="mt-4" variant="outline" onClick={() => navigate(replaceEnvironment(ROUTES.CONFIGURATION_DETAIL, item.environment))}>Manage</Button></Card>)}</div> : <InventoryEmpty title="No inventory configuration" detail="Create the development configuration through the governed API before inventory operations can be used." />}</InventoryPageShell>; }
export function ConfigurationDetailPage() {
  const { environment } = useParams(); const e = env(environment); const navigate = useNavigate(); const client = useQueryClient();
  const activationKey = useRef(createIdempotencyKey(`configuration-activate:${e}`));
  const state = useQuery({ queryKey: inventoryQueryKeys.detail(tenantId(), "configuration", e), queryFn: () => inventoryService.getConfiguration(e) });
  const activation = useMutation({ mutationFn: () => { if (!state.data) throw new Error("Configuration is not ready."); return inventoryService.activateConfiguration(e, { revision: state.data.data.active_revision, change_reason: "Activated from inventory settings" }, activationKey.current); }, onSuccess: async () => { await client.invalidateQueries({ queryKey: inventoryQueryKeys.resource(tenantId(), "configuration") }); } });
  if (state.isLoading) return <InventorySkeleton label="Loading configuration" />; if (state.error) return <InventoryErrorState error={state.error} onRetry={() => void state.refetch()} />; const record = state.data ? configDetail(state.data.data) : undefined; if (!record) return <InventoryErrorState error={new ApiError("Configuration unavailable", 404)} />;
  const mayActivate = record.allowedCommands.some((command) => command.name === "activate");
  return <InventoryPageShell title={record.title} description={record.subtitle} actions={<><Button onClick={() => navigate(replaceEnvironment(ROUTES.CONFIGURATION_EDIT, e))}>Create revision</Button>{mayActivate ? <Button disabled={activation.isPending} onClick={() => { if (window.confirm(`Activate revision ${state.data?.data.active_revision} for ${e}? Runtime inventory behavior will change without a restart.`)) activation.mutate(); }}>{activation.isPending ? "Activating…" : "Activate"}</Button> : null}<Button variant="outline" onClick={() => navigate(replaceEnvironment(ROUTES.CONFIGURATION_HISTORY, e))}>History</Button><Button variant="outline" onClick={() => navigate(replaceEnvironment(ROUTES.CONFIGURATION_IMPORT, e))}>Import</Button><Button variant="outline" onClick={() => navigate(replaceEnvironment(ROUTES.CONFIGURATION_EXPORT, e))}>Export</Button></>}>{activation.error ? <InventoryErrorState error={activation.error} /> : null}<Card className="p-5"><dl className="grid gap-5 sm:grid-cols-2">{record.fields.map((field) => <div key={field.label}><dt className="text-xs uppercase text-muted-foreground">{field.label}</dt><dd className="mt-1 font-medium">{field.value}</dd></div>)}</dl></Card></InventoryPageShell>;
}

const configDefaults = (item: InventoryConfiguration): ConfigurationUpdate => ({ default_valuation_method: item.default_valuation_method, allow_negative_stock: item.allow_negative_stock, require_stock_entry_approval: item.require_stock_entry_approval, enforce_creator_approver_separation: item.enforce_creator_approver_separation, max_lines_per_entry: item.max_lines_per_entry, reservation_ttl_minutes: item.reservation_ttl_minutes, expiry_warning_days: item.expiry_warning_days, auto_expire_batches: item.auto_expire_batches, enabled_capabilities: item.enabled_capabilities, rollout_rules: item.rollout_rules, change_reason: "" });
export function ConfigurationEditPage() { const { environment } = useParams(); const e = env(environment); const navigate = useNavigate(); const client = useQueryClient(); const state = useQuery({ queryKey: inventoryQueryKeys.detail(tenantId(), "configuration", e), queryFn: () => inventoryService.getConfiguration(e) }); const [form, setForm] = useState<ConfigurationUpdate | null>(null); const [dirty, setDirty] = useState(false); useEffect(() => { if (state.data && !form) setForm(configDefaults(state.data.data)); }, [state.data, form]); useEffect(() => { const guard = (event: BeforeUnloadEvent) => { if (dirty) { event.preventDefault(); event.returnValue = ""; } }; window.addEventListener("beforeunload", guard); return () => window.removeEventListener("beforeunload", guard); }, [dirty]); const mutation = useMutation({ mutationFn: async () => { if (!form || !state.data) throw new Error("Configuration is not ready."); if (form.max_lines_per_entry < 1 || form.max_lines_per_entry > 5000) throw new Error("Maximum entry lines must be 1–5000."); if (form.reservation_ttl_minutes < 5 || form.reservation_ttl_minutes > 10080) throw new Error("Reservation TTL must be 5–10080 minutes."); if (form.expiry_warning_days < 1 || form.expiry_warning_days > 3650) throw new Error("Expiry warning must be 1–3650 days."); if (!form.change_reason.trim()) throw new Error("A change reason is required for the audit record."); return inventoryService.createConfigurationRevision(e, form, state.data.data.version); }, onSuccess: async () => { setDirty(false); await client.invalidateQueries({ queryKey: inventoryQueryKeys.resource(tenantId(), "configuration") }); navigate(replaceEnvironment(ROUTES.CONFIGURATION_PREVIEW, e)); } }); if (state.isLoading || !form) return <InventorySkeleton label="Loading configuration editor" />; if (state.error) return <InventoryErrorState error={state.error} onRetry={() => void state.refetch()} />; const numberField = (key: "max_lines_per_entry" | "reservation_ttl_minutes" | "expiry_warning_days", label: string, min: number, max: number) => <div className="space-y-2"><Label htmlFor={key}>{label}</Label><Input id={key} type="number" min={min} max={max} value={form[key]} onChange={(event) => { setForm({ ...form, [key]: Number(event.target.value) }); setDirty(true); }} /><p className="text-xs text-muted-foreground">Safe range: {min}–{max}</p></div>; const toggle = (key: "allow_negative_stock" | "require_stock_entry_approval" | "enforce_creator_approver_separation" | "auto_expire_batches", label: string) => <label className="flex items-center gap-3 rounded-md border p-3"><input type="checkbox" checked={form[key]} onChange={(event) => { setForm({ ...form, [key]: event.target.checked }); setDirty(true); }} /><span>{label}</span></label>; return <InventoryPageShell title={`Edit ${e} configuration`} description="Saving creates an immutable revision. Preview its operational impact before activation.">{mutation.error ? <InventoryErrorState error={mutation.error} /> : null}<form onSubmit={(event) => { event.preventDefault(); mutation.mutate(); }}><Card className="grid gap-5 p-5 md:grid-cols-2">{numberField("max_lines_per_entry", "Maximum lines per stock entry", 1, 5000)}{numberField("reservation_ttl_minutes", "Default reservation TTL (minutes)", 5, 10080)}{numberField("expiry_warning_days", "Expiry warning window (days)", 1, 3650)}<div className="space-y-2"><Label htmlFor="valuation">Default valuation method</Label><select id="valuation" className="h-10 w-full rounded-md border bg-background px-3" value={form.default_valuation_method} onChange={(event) => { setForm({ ...form, default_valuation_method: event.target.value as ConfigurationUpdate["default_valuation_method"] }); setDirty(true); }}><option value="fifo">FIFO</option><option value="lifo">LIFO</option><option value="weighted_average">Weighted average</option><option value="standard_cost">Standard cost</option></select></div><div className="space-y-3 md:col-span-2">{toggle("allow_negative_stock", "Allow negative stock")}{toggle("require_stock_entry_approval", "Require stock-entry approval")}{toggle("enforce_creator_approver_separation", "Enforce creator/approver separation")}{toggle("auto_expire_batches", "Automatically expire batches")}</div><div className="space-y-2 md:col-span-2"><Label htmlFor="reason">Change reason *</Label><Input id="reason" value={form.change_reason} onChange={(event) => { setForm({ ...form, change_reason: event.target.value }); setDirty(true); }} /></div><div className="flex justify-end gap-2 md:col-span-2"><Button type="button" variant="outline" onClick={() => { if (!dirty || window.confirm("Discard unsaved changes?")) navigate(replaceEnvironment(ROUTES.CONFIGURATION_DETAIL, e)); }}>Cancel</Button><Button type="submit" disabled={mutation.isPending}>{mutation.isPending ? "Creating revision…" : "Create revision and preview"}</Button></div></Card></form></InventoryPageShell>; }

export function ConfigurationHistoryPage() { const { environment } = useParams(); const e = env(environment); const navigate = useNavigate(); const state = useQuery({ queryKey: inventoryQueryKeys.list(tenantId(), "configuration-history", { environment: e }), queryFn: () => inventoryService.configurationHistory(e) }); if (state.isLoading) return <InventorySkeleton label="Loading configuration history" />; if (state.error) return <InventoryErrorState error={state.error} onRetry={() => void state.refetch()} />; return <InventoryPageShell title={`${e} configuration history`} description="Immutable audit evidence includes actor, reason, timestamp, and correlation ID.">{state.data?.data.length ? <Card className="divide-y">{state.data.data.map((revision) => <div key={revision.id} className="flex flex-col gap-2 p-4 sm:flex-row sm:justify-between"><div><strong>Revision {revision.revision}</strong><p className="text-sm text-muted-foreground">{revision.change_reason}</p><p className="font-mono text-xs text-muted-foreground">{revision.correlation_id}</p></div><div className="text-sm text-muted-foreground">{new Date(revision.created_at).toLocaleString()}<Button className="ml-3" size="sm" variant="outline" onClick={() => navigate(`${replaceEnvironment(ROUTES.CONFIGURATION_ROLLBACK, e)}?revision=${revision.revision}`)}>Rollback</Button></div></div>)}</Card> : <InventoryEmpty title="No configuration revisions" detail="Create a configuration revision to establish an audit history." />}</InventoryPageShell>; }
export function ConfigurationPreviewPage() { const { environment } = useParams(); const e = env(environment); const state = useQuery({ queryKey: inventoryQueryKeys.detail(tenantId(), "configuration", e), queryFn: () => inventoryService.getConfiguration(e) }); const preview = useQuery({ queryKey: inventoryQueryKeys.detail(tenantId(), "configuration-preview", e), queryFn: async () => { if (!state.data) throw new Error("Configuration not loaded"); return inventoryService.previewConfiguration(e, configDefaults(state.data.data)); }, enabled: Boolean(state.data) }); if (state.isLoading || preview.isLoading) return <InventorySkeleton label="Calculating configuration impact" />; if (state.error || preview.error) return <InventoryErrorState error={state.error ?? preview.error} onRetry={() => { void state.refetch(); void preview.refetch(); }} />; return <InventoryPageShell title={`${e} configuration preview`} description="Dry-run impact is calculated by the service without persisting or activating changes.">{preview.data?.data.diff.length ? <Card className="divide-y">{preview.data.data.diff.map((item) => <div key={item.field} className="grid gap-2 p-4 sm:grid-cols-3"><strong>{item.field}</strong><span>{text(item.previous)} → {text(item.proposed)}</span><span className="text-sm text-muted-foreground">{item.behavior_impact}</span></div>)}</Card> : <InventoryEmpty title="No pending differences" detail="The proposed configuration has no changes from the effective configuration." />}</InventoryPageShell>; }
export function ConfigurationExportPage() { const { environment } = useParams(); const e = env(environment); const state = useQuery({ queryKey: inventoryQueryKeys.detail(tenantId(), "configuration-export", e), queryFn: () => inventoryService.exportConfiguration(e) }); if (state.isLoading) return <InventorySkeleton label="Preparing configuration export" />; if (state.error) return <InventoryErrorState error={state.error} onRetry={() => void state.refetch()} />; const download = () => { if (!state.data) return; const blob = new Blob([JSON.stringify(state.data.data, null, 2)], { type: "application/json" }); const href = URL.createObjectURL(blob); const anchor = document.createElement("a"); anchor.href = href; anchor.download = `inventory-${e}-configuration.json`; anchor.click(); URL.revokeObjectURL(href); }; return <InventoryPageShell title={`Export ${e} configuration`} description="The versioned document includes a server checksum for safe promotion between environments."><Card className="p-5"><p className="text-sm text-muted-foreground">Schema {state.data?.data.schema_version} · checksum <span className="font-mono">{state.data?.data.checksum}</span></p><Button className="mt-4" onClick={download}><Download className="mr-2 h-4 w-4" />Download JSON</Button></Card></InventoryPageShell>; }
export function ConfigurationImportPage() { const { environment } = useParams(); const e = env(environment); const [documentText, setDocumentText] = useState(""); const [reason, setReason] = useState(""); const key = useRef(createIdempotencyKey(`configuration-import:${e}`)); const mutation = useMutation({ mutationFn: () => { const document = JSON.parse(documentText) as Parameters<typeof inventoryService.importConfiguration>[1]["document"]; return inventoryService.importConfiguration(e, { document, change_reason: reason }, key.current); } }); return <InventoryPageShell title={`Import ${e} configuration`} description="The server validates schema, environment, checksum, permissions, and safe bounds before creating a revision.">{mutation.error ? <InventoryErrorState error={mutation.error} /> : null}<Card className="space-y-4 p-5"><div><Label htmlFor="config-document">Configuration JSON</Label><textarea id="config-document" className="mt-2 min-h-64 w-full rounded-md border bg-background p-3 font-mono text-xs" value={documentText} onChange={(event) => setDocumentText(event.target.value)} /></div><div><Label htmlFor="import-reason">Change reason</Label><Input id="import-reason" value={reason} onChange={(event) => setReason(event.target.value)} /></div><Button disabled={mutation.isPending || !documentText || !reason} onClick={() => mutation.mutate()}>{mutation.isPending ? "Validating…" : "Validate and import"}</Button></Card></InventoryPageShell>; }
export function ConfigurationRollbackPage() { const { environment } = useParams(); const [params] = useSearchParams(); const e = env(environment); const revision = Number(params.get("revision")); const [reason, setReason] = useState(""); const key = useRef(createIdempotencyKey(`configuration-rollback:${e}:${revision}`)); const mutation = useMutation({ mutationFn: () => inventoryService.rollbackConfiguration(e, { revision, change_reason: reason }, key.current) }); return <InventoryPageShell title={`Rollback ${e} configuration`} description={`Rollback creates a new immutable revision from revision ${Number.isInteger(revision) ? revision : "not selected"}; history is never rewritten.`}>{mutation.error ? <InventoryErrorState error={mutation.error} /> : null}<Card className="space-y-4 p-5"><p>This will restore the prior snapshot as a new revision. Active operations may change after activation.</p><Label htmlFor="rollback-reason">Rollback reason</Label><Input id="rollback-reason" value={reason} onChange={(event) => setReason(event.target.value)} /><Button variant="danger" disabled={!Number.isInteger(revision) || revision < 1 || !reason || mutation.isPending} onClick={() => { if (window.confirm(`Rollback ${e} inventory configuration to revision ${revision}? A new audited revision will be created.`)) mutation.mutate(); }}>{mutation.isPending ? "Rolling back…" : "Create rollback revision"}</Button></Card></InventoryPageShell>; }

export function BulkImportPage() {
  const [resourceType, setResourceType] = useState<"warehouses" | "locations" | "items" | "batches" | "serial_numbers" | "stock_entries" | "reservations" | "cycle_counts">("items");
  const [documentRef, setDocumentRef] = useState(""); const [rowCount, setRowCount] = useState(""); const key = useRef(createIdempotencyKey("bulk-import"));
  const mutation = useMutation({ mutationFn: () => inventoryService.enqueueImport({ resource_type: resourceType, document_ref: documentRef, row_count: Number(rowCount) }, key.current) });
  return <InventoryPageShell title="Import inventory data" description="Queue a durable, validated import. Acceptance is reported only after the job and outbox event exist.">{mutation.error ? <InventoryErrorState error={mutation.error} /> : null}{mutation.data ? <Card className="p-5" role="status"><h2 className="font-semibold">Import queued</h2><p className="mt-1 text-sm text-muted-foreground">Job {mutation.data.data.id} · {mutation.data.data.status}</p><p className="mt-1 font-mono text-xs text-muted-foreground">Correlation ID: {mutation.data.correlationId}</p></Card> : null}<Card className="grid gap-5 p-5 sm:grid-cols-2"><div className="space-y-2"><Label htmlFor="resource-type">Resource type</Label><select id="resource-type" className="h-10 w-full rounded-md border bg-background px-3" value={resourceType} onChange={(event) => setResourceType(event.target.value as typeof resourceType)}><option value="warehouses">Warehouses</option><option value="locations">Locations</option><option value="items">Items</option><option value="batches">Batches</option><option value="serial_numbers">Serial numbers</option><option value="stock_entries">Stock entries</option><option value="reservations">Reservations</option><option value="cycle_counts">Cycle counts</option></select></div><div className="space-y-2"><Label htmlFor="row-count">Validated row count</Label><Input id="row-count" type="number" min="1" value={rowCount} onChange={(event) => setRowCount(event.target.value)} /></div><div className="space-y-2 sm:col-span-2"><Label htmlFor="document-ref">Uploaded document reference</Label><Input id="document-ref" value={documentRef} onChange={(event) => setDocumentRef(event.target.value)} /><p className="text-xs text-muted-foreground">Use the immutable reference returned by the platform document upload flow.</p></div><div className="sm:col-span-2 flex justify-end"><Button disabled={mutation.isPending || !documentRef || Number(rowCount) < 1} onClick={() => mutation.mutate()}>{mutation.isPending ? "Creating durable job…" : "Queue validated import"}</Button></div></Card></InventoryPageShell>;
}

function TracePage({ kind }: { kind: "batch" | "serial" }) { const { id = "" } = useParams(); const state = useQuery({ queryKey: inventoryQueryKeys.detail(tenantId(), `${kind}-trace`, id), queryFn: () => kind === "batch" ? inventoryService.traceBatch(id) : inventoryService.traceSerial(id) }); if (state.isLoading) return <InventorySkeleton label={`Loading ${kind} trace`} />; if (state.error) return <InventoryErrorState error={state.error} onRetry={() => void state.refetch()} />; return <InventoryPageShell title={`${kind === "batch" ? "Batch" : "Serial"} trace`} description="Chronological, immutable custody and valuation evidence from the stock ledger.">{state.data?.data.length ? <Card className="divide-y">{state.data.data.map((entry) => <div key={entry.id} className="grid gap-2 p-4 sm:grid-cols-4"><strong>#{entry.sequence}</strong><span>{entry.warehouse.name} / {entry.location.name}</span><span>{entry.quantity_delta} units</span><time>{new Date(entry.posted_at).toLocaleString()}</time></div>)}</Card> : <InventoryEmpty title="No posted movements" detail={`This ${kind} has no visible ledger history in the current tenant.`} />}</InventoryPageShell>; }

